VALUES
  ('disabled-c5fb3965-moex-00261', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-112-3082b5f1', 'sub-disabled-c5fb3965-08', NULL, 'single_choice', '關於國家賠償之敘述，下列何者錯誤？', '["法官因執行職務侵害人民自由或權利，就其參與審判或追訴案件犯職務 上之罪，經判決有罪確定者，有國家賠償法規定之適用", "檢察官因執行職務侵害人民自由或權利，就其參與審判或追訴案件犯職 務上之罪，經判決有罪確定者，有國家賠償法規定之適用", "警察機關以契約委託民間拖吊業者執行拖吊違規車輛，造成受拖吊車主 之損害，該車主可向執行之警察機關主張國家賠償", "甲為私法人之民間基金會，其雖受乙行政機關委託執行公權力，但因甲 為私法人，故人民不得對其主張國家賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00262', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-112-3082b5f1', 'sub-disabled-c5fb3965-08', NULL, 'single_choice', '關於徵收補償之憲法內涵，依照司法院解釋，下列敘述何者正確？', '["徵收處分作成後，如未於法定期限內發給補償，該處分失效", "補償與損失必須一致，故應採完全補償原則", "基於財產權之價值保障，補償方式限以金錢為之", "補償之對象，限於土地所有權人，不及於該土地之其他財產權人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00263', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-de0a21a2', 'sub-disabled-c5fb3965-06', NULL, 'essay', '甲罹患絕症，不久人世。為了最後一次為母親慶生，甲前往乙經營的烘焙
坊訂購生日蛋糕，當場付清款項，約定在慶生當天乙店打烊前自行取貨。
未料甲當天身體不適昏倒路旁，被路人送醫急救，清醒時已經過了乙店打
烊時間。甲強忍著身體不適前往乙店，從門外看到所訂購的蛋糕擺放在冷
藏櫃裡，但不得其門而入。甲嘗試聯絡乙本人未果，眼看與母親約定的慶
生時間已到，只好拿石塊敲破乙店的玻璃大門，進門取走蛋糕。請詳述甲
的刑責如何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "0281b73b72bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00264', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-de0a21a2', 'sub-disabled-c5fb3965-06', NULL, 'essay', '甲為法律系教授，與擔任市政府公務員的乙是大樓同層鄰居。乙的小孩丙
經常在深夜大聲喧嘩，甲的工作與睡眠都受到嚴重干擾。乙多次向甲致歉，
表示丙都不聽其口頭勸告。甲對乙面帶嚴肅地表示，父母依法對未成年子
女有懲戒權，可以對不聽話的小孩施加體罰，程度不拘。當丙又深夜大聲
喧嘩時，聽信甲所言的乙，果真拿藤條將丙痛打到全身瘀青。甲出門巧遇
傷勢嚴重的丙，才得知其玩笑話竟被乙當真，深感歉疚。請詳述甲、乙的
刑責如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "0281b73b72bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00265', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-de0a21a2', 'sub-disabled-c5fb3965-06', NULL, 'essay', '甲因為持有海洛因被警方逮捕，警詢時表示海洛因是向毒販乙所購買。警
方推測乙可能將海洛因存放在住處，未向法院聲請搜索票就大隊人馬前往
乙宅。乙恰好不在家，由同住的乙妻應門。警員丙語氣緩和地徵求乙妻同
意進屋搜索。乙妻覺得有點不妥，卻又不敢得罪警察，只好任由警察進屋。
警員果真在儲藏室裡找到乙藏匿的海洛因，當場扣押，離去前並請乙妻在
搜索筆錄上簽名。檢察官以警方在乙宅扣押的海洛因及甲的證詞為證據，
起訴乙販賣第一級毒品罪。乙的辯護人在審判中抗辯扣案的海洛因無證據
能力，請詳述乙的辯護人抗辯有無理由。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "0281b73b72bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00266', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-de0a21a2', 'sub-disabled-c5fb3965-06', NULL, 'essay', '檢察官以被告A涉嫌殺人罪起訴，A在臺灣臺南地方法院獲判有罪，上訴
臺灣高等法院臺南分院，由法官甲、乙、丙組成合議庭審理。受命法官甲
在臺灣臺南地方法院任職期間，曾經參與本案第一審審判期日的證據調查
程序，並在審判中裁定延長羈押A，後來因為調職臺灣高等法院臺南分院，
未參與本案的第一審判決。被告A認為甲曾經參與過本案的第一審審判程
序，已經不可能保持客觀中立，故聲請法官甲迴避，請詳述A的聲請有無
理由。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "0281b73b72bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00267', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-0e0a3822', 'sub-disabled-c5fb3965-07', NULL, 'essay', 'A於今年（以下同）三月一日出借自己收藏名畫家倪瓚的「岸南雙樹圖」一
幅畫給B觀賞，B於三月三日擅行讓售該畫於不知情之C，C當晚再將之讓
售於惡意之D，並即交付之。試問：D依法是否取得該畫之所有權？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "f37b217b4768", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與親屬編", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00268', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-0e0a3822', 'sub-disabled-c5fb3965-07', NULL, 'essay', '父甲贈與二十張台積電股票，給其四歲之子乙，並以乙之名義存放於 A銀
行之保險箱內。半年後，甲因經商失敗，其債權人丙就該二十張台積電股
票，在民法上可以主張那些權利？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "f37b217b4768", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與親屬編", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00269', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-0e0a3822', 'sub-disabled-c5fb3965-07', NULL, 'essay', '夫妻未約定夫妻財產制，妻提起離婚訴訟後，兩造依民事訴訟法達成訴訟上
和解離婚成立。夫妻一方嗣後向他造請求分配剩餘財產時，夫妻現存之婚後
財產之價值計算，應以起訴時為準，或以訴訟上和解成立時為準？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "f37b217b4768", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與親屬編", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00270', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-0e0a3822', 'sub-disabled-c5fb3965-07', NULL, 'essay', '甲男與乙女於民國（以下同）八十五年元旦結婚，結婚之後二人生下丙、
丁二子，然因甲、乙感情不睦，甲男遂與前女友戊發生合意性交行為，自
八十八年三月間迄今，乙女雖於九十一年三月間發現後，為了家庭和諧，
一再容忍甲、戊之婚外親密行為，嗣甲在一一〇年元旦向乙表示，希望乙
能答應甲納戊為小老婆，三人一起共同生活，乙實無法容忍，遂於同年三
月八日向法院起訴請求與甲離婚，經法院調解不成立，法院開庭審理本案
時，甲抗辯：乙早已知悉伊與戊之關係，事後已予宥恕，不得請求離婚等
語，是否有理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "f37b217b4768", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與親屬編", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
